<script setup lang="ts">import { ref } from 'vue'; import { useRouter } from 'vue-router'; import { Delete } from 'lucide-vue-next'; import { useAppStore } from '../store'; const store=useAppStore(), router=useRouter(), pin=ref(''), error=ref(''); function key(v:string){if(v==='back')pin.value=pin.value.slice(0,-1);else if(pin.value.length<4)pin.value+=v;if(pin.value.length===4){if(store.verifyPin(pin.value))router.replace('/parent');else{error.value='PIN 不正确，请重新输入。';pin.value=''}}}</script>
<template><main class="page pin-page"><header class="page-header"><small>家长空间</small><h1>输入家长 PIN</h1><p>默认演示 PIN 为 2580</p></header><div class="pin-dots"><i v-for="n in 4" :key="n" :class="{filled:n<=pin.length}"/></div><p class="form-error">{{error}}</p><div class="keypad"><button v-for="v in ['1','2','3','4','5','6','7','8','9','back','0','']" :key="v" :disabled="!v" @click="key(v)"><Delete v-if="v==='back'"/><span v-else>{{v}}</span></button></div></main></template>
